package concrete.goonie.chart.api.data; import concrete.goonie.chart.api.data.render.TextDataSetRenderer; import concrete.goonie.chart.api.model.Timeframe; import concrete.goonie.chart.internal.render.*; public final class TextDataSet extends DataSet { private final double[] xValues,yValues; private final String[] texts; private final TextDataSetRenderer renderer = new TextDataSetRenderer(); private Style textStyle = new Style(0xFFE2E8F0,1f,false); public TextDataSet(String name, double[] xValues, double[] yValues, String[] texts, Timeframe... timeframes){ super(name,DataSetType.TEXT,timeframes); this.xValues=xValues; this.yValues=yValues; this.texts=texts; } public int sizeValue(){ return xValues.length; } public double xValue(int i){ return xValues[i]; } public double yValue(int i){ return yValues[i]; } public String text(int i){ return texts[i]; } public Style getTextStyle(){ return textStyle; } public void setTextStyle(Style s){ this.textStyle=s; } @Override public void render(RenderList out, Transform t, int visibleFrom, int visibleTo){ renderer.render(this,out,t,visibleFrom,visibleTo); } }